import { EventEmitter } from 'events';
import { FILE_DELETED_EVENT, FileDeletedEventPayload } from '../types';

// Define a custom EventEmitter to type-check events
class AppEventEmitter extends EventEmitter {
  emit(eventName: typeof FILE_DELETED_EVENT, payload: FileDeletedEventPayload): boolean;
  emit(eventName: string | symbol, ...args: any[]): boolean {
    return super.emit(eventName, ...args);
  }

  on(eventName: typeof FILE_DELETED_EVENT, listener: (payload: FileDeletedEventPayload) => void): this;
  on(eventName: string | symbol, listener: (...args: any[]) => void): this {
    return super.on(eventName, listener);
  }

  once(eventName: typeof FILE_DELETED_EVENT, listener: (payload: FileDeletedEventPayload) => void): this;
  once(eventName: string | symbol, listener: (...args: any[]) => void): this {
    return super.once(eventName, listener);
  }
}

// Export a singleton instance
export const appEventEmitter = new AppEventEmitter();
