import { File } from '../types';

// --- Simulate a Database ---
// In a real application, this would interact with a database (e.g., PostgreSQL, MongoDB)
// and an object storage service (e.g., S3, Google Cloud Storage, local disk).
const files: File[] = [
  {
    id: 'file-123',
    name: 'document.pdf',
    path: 'uploads/document.pdf',
    createdAt: new Date(),
    updatedAt: new Date(),
  },
  {
    id: 'file-456',
    name: 'image.jpg',
    path: 'uploads/image.jpg',
    createdAt: new Date(),
    updatedAt: new Date(),
  },
];

export class FileService {
  /**
   * Simulates soft-deleting a file in the database.
   * Marks the file as deleted by setting `deletedAt`.
   * @param fileId The ID of the file to soft-delete.
   * @returns The updated File object if found and deleted, otherwise null.
   */
  async softDeleteFile(fileId: string): Promise<File | null> {
    const fileIndex = files.findIndex((f) => f.id === fileId && !f.deletedAt);

    if (fileIndex === -1) {
      return null; // File not found or already deleted
    }

    const file = files[fileIndex];
    file.deletedAt = new Date();
    file.updatedAt = new Date();

    console.log(`[DB] File '${file.id}' soft-deleted at ${file.deletedAt.toISOString()}`);
    return { ...file }; // Return a copy
  }

  /**
   * Simulates asynchronously deleting the actual object from storage.
   * This operation is typically performed by a separate worker or process
   * after the database record has been updated and an event emitted.
   * @param filePath The path to the object in storage.
   */
  async deleteObjectStorage(filePath: string): Promise<void> {
    return new Promise((resolve) => {
      // Simulate an asynchronous I/O operation (e.g., network request to S3)
      setTimeout(() => {
        console.log(`[Storage] Object at path '${filePath}' asynchronously deleted.`);
        // In a real scenario, you'd call your storage client here:
        // await s3Client.deleteObject({ Bucket: 'my-bucket', Key: filePath });
        resolve();
      }, 1000); // Simulate 1 second delay for storage deletion
    });
  }
}

export const fileService = new FileService();
