import { Hono } from 'hono';
import { fileService } from './services/fileService';
import { appEventEmitter } from './events/eventEmitter';
import { FILE_DELETED_EVENT, FileDeletedEventPayload } from './types';

const app = new Hono();

// --- Event Listener for Asynchronous Object Deletion ---
appEventEmitter.on(FILE_DELETED_EVENT, async (payload: FileDeletedEventPayload) => {
  console.log(`[Event] Received '${FILE_DELETED_EVENT}' for file ID: ${payload.fileId}`);
  try {
    await fileService.deleteObjectStorage(payload.filePath);
    console.log(`[Event] Asynchronous object deletion completed for file ID: ${payload.fileId}`);
  } catch (error) {
    console.error(`[Event] Failed to delete object for file ID: ${payload.fileId}, path: ${payload.filePath}`, error);
    // In a real application, you might want to retry this operation or log it to a dead-letter queue.
  }
});

// --- Soft-Delete File Route ---
app.delete('/files/:id', async (c) => {
  const fileId = c.req.param('id');

  console.log(`[API] Attempting soft-delete for file ID: ${fileId}`);

  const deletedFile = await fileService.softDeleteFile(fileId);

  if (!deletedFile) {
    console.log(`[API] File ID: ${fileId} not found or already deleted.`);
    return c.json({ message: 'File not found or already deleted' }, 404);
  }

  // Emit event for asynchronous object deletion
  appEventEmitter.emit(FILE_DELETED_EVENT, {
    fileId: deletedFile.id,
    filePath: deletedFile.path,
  });

  console.log(`[API] File ID: ${fileId} soft-deleted and '${FILE_DELETED_EVENT}' event emitted.`);

  return c.json({
    message: 'File soft-deleted successfully. Object deletion initiated asynchronously.',
    fileId: deletedFile.id,
  }, 200);
});

// --- Basic Health Check / Root Route ---
app.get('/', (c) => {
  return c.text('Hono App is running!');
});

// --- Start the Server ---
const port = 3000;
console.log(`Server is running on http://localhost:${port}`);

export default {
  port,
  fetch: app.fetch,
};

/*
To run this example:
1. Save the files as src/types.ts, src/events/eventEmitter.ts, src/services/fileService.ts, src/index.ts
2. Install dependencies: `npm install hono`
3. Create a `package.json` with `type: module` and a start script:
   ```json
   {
     "name": "aether-file-delete",
     "version": "1.0.0",
     "description": "File soft-delete with async object deletion and event emission",
     "main": "src/index.ts",
     "scripts": {
       "start": "node --loader ts-node/esm src/index.ts"
     },
     "keywords": [],
     "author": "",
     "license": "ISC",
     "dependencies": {
       "hono": "^4.0.0"
     },
     "devDependencies": {
       "ts-node": "^10.9.2",
       "typescript": "^5.3.3"
     }
   }
   ```
4. Run: `npm start`

Test with curl:
- Soft-delete an existing file:
  `curl -X DELETE http://localhost:3000/files/file-123`
- Try to delete a non-existent file:
  `curl -X DELETE http://localhost:3000/files/non-existent-file`
- Try to delete an already deleted file (will return 404 as per current logic):
  `curl -X DELETE http://localhost:3000/files/file-123` (after the first successful delete)
*/
```

